VALUES
  ('fire-eq-eng-moex-00111', 'fire-eq-eng', 'fire-eq-eng-moex-105-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依據防火牆及防火水幕設置基準規定，有關防火水幕設備之水源容量，下列敘述何者錯誤？', '["儲槽容量未達一萬公秉者，不得小於防護該儲槽連續放水一百二十分鐘之水量", "儲槽容量達一萬公秉以上者，不得小於防護該儲槽連續放水二百分鐘之水量", "消防用水與普通用水合併使用者，應採取必要措施，確保水源容量在有效水量範圍內", "水源與其他滅火設備水源併設時，其總容量不得小於防護同一儲槽各滅火設備應設水量之合計"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:21+00:00", "source_pdf_sha1": "d61916da2964", "answer_pdf_sha1": "82aa81c917b6", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00112', 'fire-eq-eng', 'fire-eq-eng-moex-105-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依據防火牆及防火水幕設置基準規定，有一儲槽容量為八千公秉，其防火水幕設備之緊急電源供電容量 時間為何？', '["三十分鐘", "六十分鐘", "一百八十分鐘", "三百六十分鐘"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:21+00:00", "source_pdf_sha1": "d61916da2964", "answer_pdf_sha1": "82aa81c917b6", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00113', 'fire-eq-eng', 'fire-eq-eng-moex-105-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依據可燃性高壓氣體儲存場所防爆牆設置基準規定，下列敘述何者錯誤？', '["防爆牆長度應超過設置方位儲存場所建築物牆面長度。其牆腳與儲存場所建築物之距離不得少於二公尺", "防爆牆分為鋼筋混凝土製、混凝土空心磚製及鋼板製等三種，並應設置於堅固基礎上", "防爆牆對被波及處之耐火及延燒應具有充分阻絕效果", "防爆牆之設置應與各設備保持適當距離，不得妨礙火災時之滅火行動"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:21+00:00", "source_pdf_sha1": "d61916da2964", "answer_pdf_sha1": "82aa81c917b6", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00114', 'fire-eq-eng', 'fire-eq-eng-moex-105-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依據各類場所消防安全設備設置標準規定，有關密閉式撒水頭之自動撒水設備末端之查驗閥，下列敘述 何者錯誤？', '["查驗閥管徑在二十五毫米以上", "查驗閥接裝在建築物各層放水壓力最低之最遠支管末端", "查驗閥之一次側設有與撒水頭同等放水性能之限流孔，二次側設壓力表", "查驗閥距離地板面之高度在二點一公尺以下，並附有排水管裝置"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:21+00:00", "source_pdf_sha1": "d61916da2964", "answer_pdf_sha1": "82aa81c917b6", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00115', 'fire-eq-eng', 'fire-eq-eng-moex-105-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依據消防機關辦理建築物消防安全設備審查及查驗作業基準規定，下列有關建築物消防安全設備竣工查 驗程序敘述何者錯誤？', '["起造人填具申請書，檢附消防安全設備測試報告書、安裝施工測試照片、證明文件、使用執照申請書、 原審訖之消防圖說等，向當地消防機關提出，資料不齊全者，消防機關通知限期補正", "消防安全設備裝置人攜帶消防安全設備測試報告書至竣工現場配合查驗，消防安全設備裝置人無正當 理由未會同查驗者，得予退件", "竣工查驗不合規定者，消防機關應製作查驗紀錄表，將不合規定項目詳為列舉一次告知起造人，起造 人於完成改善後應通知消防機關複查，其經複查仍不符合規定者，消防機關得將該申請案函退", "竣工現場設置之消防安全設備與原審訖消防圖說之設備數量或位置有異動時，於不影響設備功能及性 能之情形下，得直接修改竣工圖，並於申請查驗時，備具完整竣工消防圖說，一次報驗"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:21+00:00", "source_pdf_sha1": "d61916da2964", "answer_pdf_sha1": "82aa81c917b6", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00116', 'fire-eq-eng', 'fire-eq-eng-moex-105-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依據緊急廣播設備用揚聲器認可基準規定，採用依各類場所消防安全設備設置標準第133條第3款性能 設計之緊急廣播設備揚聲器，其標示應加註下列何項？', '["耐電壓等級", "指向特性區分", "音壓頻率等級", "耐燃性等級"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:21+00:00", "source_pdf_sha1": "d61916da2964", "answer_pdf_sha1": "82aa81c917b6", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00117', 'fire-eq-eng', 'fire-eq-eng-moex-105-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依據各類場所消防安全設備設置標準規定，有關移動式泡沫滅火設備，下列敘述何者錯誤？', '["移動式泡沫滅火設備之泡沫原液，應使用高發泡", "同一樓層各泡沫瞄子放射量，應在每分鐘一百公升以上。但全部泡沫消防栓箱數量超過二個時，以同 時使用二支泡沫瞄子計算之", "泡沫瞄子放射壓力應在每平方公分三點五公斤以上或0.35MPa以上", "泡沫消防栓箱其箱面表面積應在零點八平方公尺以上，標明移動式泡沫滅火設備字樣，其上方設置紅 色幫浦啟動表示燈"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:21+00:00", "source_pdf_sha1": "d61916da2964", "answer_pdf_sha1": "82aa81c917b6", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00118', 'fire-eq-eng', 'fire-eq-eng-moex-105-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依據建築技術規則建築設計施工編規定，下列敘述何者錯誤？①一宗土地指一幢或二幢以上有連帶使用', '["阻熱性為在標準耐火試驗條件下，建築構造當其一面受火時，能在一 定時間內，其非加熱面溫度不超過規定值之能力", "同一室內之天花板高度不同時，以其室內天花板平 均高度作天花板高度", "同一樓層內夾層面積之和，超過該層樓地板面積三分之一或一百平方公尺者， 視為另一樓層  ⑤避難層為具有出入口通達基地地面或道路之樓層  ⑥分間牆：分隔住宅單位與住宅單 位或住戶與住戶或不同用途區劃間之牆壁", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:21+00:00", "source_pdf_sha1": "d61916da2964", "answer_pdf_sha1": "82aa81c917b6", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 32, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00119', 'fire-eq-eng', 'fire-eq-eng-moex-105-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依據建築技術規則建築設計施工編規定，「在常溫及中溫標準試驗條件下，建築物出入口裝設之一般門 或區劃出入口裝設之防火設備，當其構造二側形成火災情境下之壓差時，具有漏煙通氣量不超過規定值 之能力」，上述用語定義係指下列何者？', '["防火時效", "阻熱性", "遮煙性能", "耐燃性"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:21+00:00", "source_pdf_sha1": "d61916da2964", "answer_pdf_sha1": "82aa81c917b6", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00120', 'fire-eq-eng', 'fire-eq-eng-moex-105-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依據各類場所消防安全設備設置標準規定，下列有關無線電通信輔助設備之接頭敘述何者錯誤？', '["設於距樓地板面或基地地面高度零點三公尺至一點五公尺間", "裝設於保護箱內，箱內設長度二公尺以上之射頻電纜，其箱面應漆紅色，並標明消防隊專用無線電接 頭字樣", "設於地面消防人員便於取用處及值日室等平時有人之處所", "設於地面之接頭數量，在任一出入口與其他出入口之步行距離大於三百公尺時，設置二個以上"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:21+00:00", "source_pdf_sha1": "d61916da2964", "answer_pdf_sha1": "82aa81c917b6", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL)
